  async function handleSubmit() {
    if (!accessToken) {
      setError("Merchant session missing. Please sign in again.");
      return;
    }
    if (!form.name.trim()) {
      setError(language === "bn" ? "?????? ??? ??????" : "Product name is required.");
      return;
    }

    const payload = {
      name: form.name.trim(),
      category: form.category.trim() || "General",
      price: toNumber(form.price),
      costPrice: toNumber(form.costPrice),
      stock: toNumber(form.stock),
      barcode: form.barcode.trim() || undefined,
      imageUrl: form.imageUrl.trim() || undefined,
      discountRate: toNumber(form.discountRate),
      productionDate: form.productionDate || undefined,
      expiryDate: form.expiryDate || undefined,
    };

    setError(null);
    try {
      if (editingId) {
        await updateMerchantProductRequest(accessToken, editingId, payload);
        console.log("[merchant-products] submit:update-success", JSON.stringify({ id: editingId, name: payload.name }));
        setStatus(language === "bn" ? `${form.name.trim()} ????? ??????` : `${form.name.trim()} updated.`);
      } else {
        await createMerchantProductRequest(accessToken, payload);
        console.log("[merchant-products] submit:create-success", JSON.stringify({ name: payload.name }));
        setStatus(language === "bn" ? `${form.name.trim()} ??? ??????` : `${form.name.trim()} created.`);
      }
      setEditingId(null);
      setForm(EMPTY_FORM);
      setSearchQuery("");
      setSortMode("LATEST");
      setVisibleCount(10);
      await loadProducts();
    } catch (submitError) {
      console.log("[merchant-products] submit:error", submitError instanceof Error ? submitError.message : String(submitError));
      setError(submitError instanceof Error ? submitError.message : "Unable to save product.");
    }
  }

